        /// <summary>
        /// The child document
        /// </summary>
        public class ChildrenModel
        {
            /// <summary>
            /// Gets or sets the name.
            /// </summary>
            /// <value>
            /// The name.
            /// </value>
            public string Name { get; set; }
        }
        #endregion
    }
}
